I'd like to make a small change to support asynchronous clients, such as asyncio, Tornado, Twisted, curio, etc. I found that only one change was required in order to get something working. If I add the following to `transport.py` at [line 325](https://github.com/elastic/elasticsearch-py/blob/master/elasticsearch/transport.py#L325):

```python
connection_is_async = getattr(connection, 'IS_ASYNC', False)

if connection_is_async:
    return connection.perform_request(method, url, params, body, ignore=ignore, timeout=timeout)
```

...then I can use an async connection to talk to ES.

This change turns out to be similar to many of the changes in [this merge](https://github.com/elastic/elasticsearch-py/commit/b10ae7c891f7cba690b58c957145f9b6d9acb4ca) of the `async` branch on Mar 22nd.

Namely, that instead of pulling out the arguments from `perform_request`, we just return the whole result. This allows an async connection to return a future, a task, a deferred, etc.

Although returning early here bypasses some subsequent logic, that logic is mainly for retries and connection pooling; an event loop can handle the former trivially, and has no need of the latter.

With the change above I am able to implement something with [treq](https://github.com/twisted/treq) like so:

```python
import base64
import urlparse

import treq

from elasticsearch import Elasticsearch
from twisted.internet import reactor
from twisted.internet.defer import (
    inlineCallbacks as inline,
    returnValue,
    maybeDeferred
)

from environ import ELASTICSEARCH_URL


class Client(object):

    def __init__(self, host, client=treq):

        self.host = host
        self.parsed = urlparse.urlparse(host)

        token = base64.b64encode('{}:{}'.format(
            self.parsed.username,
            self.parsed.password
        ))

        self.url = '{scheme}://{host}:{port}'.format(
            scheme=self.parsed.scheme,
            host=self.parsed.hostname,
            port=self.parsed.port
        )

        self.headers = {
            'Authorization': 'Basic {}'.format(token)
        }

        self.client = client

    @inline
    def _check_response(self, response):

        if 200 <= response.code < 300:

            try:
                data = yield response.json()
            except ValueError:
                data = yield response.text()

            returnValue(data)

        error = yield response.content()
        msg = "resp code: {}; details:\n{}".format(response.code, error)

        raise Exception(msg)

    @inline
    def get(self, url, body=None, params=None, ignore=None, timeout=None):

        response = yield maybeDeferred(
            self.client.get,
            "{}/{}".format(self.url, url),
            data=body,
            params=params,
            headers=self.headers,
            timeout=timeout
        )

        result = yield self._check_response(response)

        returnValue(result)


class Connection(object):

    IS_ASYNC = True

    def __init__(self, host, Client=Client):

        self.client = Client(host)

        methods = ['GET', 'PUT', 'POST', 'PATCH', 'DELETE', 'HEAD']

        self.dispatch = {
            m: getattr(self.client, m.lower(), self.default) for m in methods
        }

    def __call__(self):

        return self

    def default(*args, **kwargs):
            raise Exception("Not implemented")

    def perform_request(self, method, url,
                        params=None, body=None, ignore=None, timeout=None):

        return self.dispatch.get(method, self.default)(
            url, body, params, ignore, timeout
        )


@inline
def main():

    connection = Connection(host=ELASTICSEARCH_URL)
    elastic = Elasticsearch(connection_class=connection)

    result = yield elastic.search(
        index="a",
        doc_type="b",
        body={"query": {"match": {"c": 'd'}}},
        size=1,
        sort=['f']
    )

    print (result)

    reactor.stop()

if __name__ == "__main__":

    reactor.callWhenRunning(main)
    reactor.run()

```

